const plan = $('Claude Plans Directory Architecture').item.json.content[0].text;
const structuredData = JSON.parse($('Claude Structures Data').item.json.content[0].text.replace(/```json|```/g,'').trim());
const input = $('Manual Trigger').item.json;

// Store to AFFiNE via filesystem (Claude Code will read this)
const claudeMd = `# DIRECTORY BUILD TASK
## Niche: ${input.niche}
## Brand: ${input.brand_name} (${input.brand_url})
## Listings: ${structuredData.total_count}
## Categories: ${structuredData.categories?.join(', ')}

## ARCHITECTURE PLAN
${plan}

## DATA SNAPSHOT (first 5 listings)
${JSON.stringify(structuredData.listings?.slice(0,5), null, 2)}

## CLAUDE CODE INSTRUCTIONS

Build this directory with:
1. Next.js 14 App Router
2. Postgres via Prisma (schema from plan above)
3. Meilisearch for instant search
4. All listing pages: /[category]/[slug]
5. Compare pages: /compare/[slug1]-vs-[slug2]
6. Category pages: /[category]
7. Schema.org JSON-LD on every page
8. Brand sponsor widget on every listing (${input.brand_name})
9. sitemap.xml auto-generated
10. robots.txt with sitemap reference

Run: AGENT: --dangerouslySkipPermissions build this entire directory`;

return {
  claudeMd,
  listings: structuredData.listings,
  categories: structuredData.categories,
  niche: input.niche,
  brand: input.brand_name,
  brand_url: input.brand_url
};

// Directory submission targets with their submission URLs
const directories = [
  { name: 'ProvenExpert', url: 'https://www.provenexpert.com', api: null, method: 'form' },
  { name: 'AlternativeTo', url: 'https://alternativeto.net/platform/web-apps/suggest', api: null, method: 'form' },
  { name: 'Product Hunt', url: 'https://www.producthunt.com/posts/new', api: 'https://api.producthunt.com', method: 'api' },
  { name: 'BetaList', url: 'https://betalist.com/startups/new', api: null, method: 'form' },
  { name: 'Crunchbase', url: 'https://www.crunchbase.com/add-company', api: null, method: 'form' },
  { name: 'AppSumo', url: 'https://appsumo.com/partner', api: null, method: 'form' },
  { name: 'G2', url: 'https://www.g2.com/products/new', api: null, method: 'form' },
  { name: 'Capterra', url: 'https://www.capterra.com/vendors/sign-up', api: null, method: 'form' },
  { name: 'GetApp', url: 'https://www.getapp.com/directory/submit', api: null, method: 'form' },
  { name: 'SoftwareSuggest', url: 'https://www.softwaresuggest.com/vendor', api: null, method: 'form' }
];
const input = $('Prepare Claude Code Build').item.json;
return directories.map(d => ({ ...d, site_name: input.niche + ' Directory', brand: input.brand, niche: input.niche }));

// Build IndexNow submission payload
// Assumes directory is deployed at: https://[niche]-directory.yourdomain.com
const input = $('Prepare Claude Code Build').item.json;
const domain = input.niche.toLowerCase().replace(/ /g,'-') + '-directory.' + ($env.BASE_DOMAIN || 'yourdomain.com');
const listings = input.listings || [];

// Generate URL list for all pages
const urls = [];
urls.push('https://' + domain); // homepage
const categories = [...new Set(listings.map(l => l.category))];
categories.forEach(cat => {
  if (cat) urls.push('https://' + domain + '/' + cat.toLowerCase().replace(/ /g,'-'));
});
listings.slice(0, 200).forEach(l => {
  if (l.category && l.slug) {
    urls.push('https://' + domain + '/' + l.category.toLowerCase().replace(/ /g,'-') + '/' + l.slug);
  }
});

// Batch into groups of 100 for drip submission
const batches = [];
for (let i = 0; i < urls.length; i += 100) {
  batches.push(urls.slice(i, i+100));
}
return batches.map((batch, i) => ({ batch_number: i+1, total_batches: batches.length, urls: batch, domain, key: $env.INDEXNOW_KEY || 'your-indexnow-key' }));
